namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
                Ingredients = ["Baguette", "Tomatoes", "Fresh basil", "Garlic", "Olive oil", "Salt"],
                Steps = ["Slice and toast the baguette.", "Dice tomatoes and mix with chopped basil, minced garlic, and olive oil.", "Spoon mixture onto toasted bread and serve."],
                AverageRating = 4.5, RatingCount = 12
            },
            new Recipe
            {
                Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
                Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parmesan", "Breadcrumbs", "Parsley"],
                Steps = ["Remove mushroom stems and hollow caps.", "Mix cream cheese, garlic, parmesan, and breadcrumbs.", "Fill caps and bake at 375°F for 20 minutes."],
                AverageRating = 4.2, RatingCount = 8
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper"],
                Steps = ["Cook spaghetti until al dente.", "Fry pancetta until crispy.", "Whisk eggs with grated parmesan.", "Toss hot pasta with pancetta, then stir in egg mixture off heat.", "Season with black pepper and serve immediately."],
                AverageRating = 4.8, RatingCount = 25
            },
            new Recipe
            {
                Id = 4, Title = "Chicken Tikka Masala", Category = "Main Courses", CategorySlug = "main-courses",
                Ingredients = ["Chicken breast", "Yogurt", "Tikka spice mix", "Onion", "Tomato sauce", "Cream", "Rice"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-fry chicken pieces.", "Sauté onions, add tomato sauce and cream.", "Combine chicken with sauce and simmer 10 minutes.", "Serve over basmati rice."],
                AverageRating = 4.7, RatingCount = 19
            },
            new Recipe
            {
                Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
                Steps = ["Melt chocolate and butter together.", "Whisk eggs and sugar until fluffy.", "Fold in melted chocolate and flour.", "Pour into greased ramekins.", "Bake at 425°F for 12 minutes. Center should be soft."],
                AverageRating = 4.9, RatingCount = 30
            },
            new Recipe
            {
                Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
                Ingredients = ["Ladyfingers", "Espresso", "Mascarpone", "Eggs", "Sugar", "Cocoa powder"],
                Steps = ["Brew espresso and let cool.", "Whisk egg yolks with sugar, fold in mascarpone.", "Dip ladyfingers in espresso and layer in dish.", "Spread mascarpone mixture over ladyfingers.", "Repeat layers, dust with cocoa, and refrigerate 4 hours."],
                AverageRating = 4.6, RatingCount = 15
            },
            new Recipe
            {
                Id = 7, Title = "Mango Lassi", Category = "Beverages", CategorySlug = "beverages",
                Ingredients = ["Mango", "Yogurt", "Milk", "Sugar", "Cardamom"],
                Steps = ["Blend mango, yogurt, milk, sugar, and cardamom until smooth.", "Serve chilled."],
                AverageRating = 4.3, RatingCount = 10
            },
            new Recipe
            {
                Id = 8, Title = "Guacamole & Chips", Category = "Snacks", CategorySlug = "snacks",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Onion", "Jalapeño", "Tortilla chips"],
                Steps = ["Mash avocados with lime juice.", "Stir in diced onion, cilantro, and jalapeño.", "Season with salt and serve with tortilla chips."],
                AverageRating = 4.4, RatingCount = 18
            },
            new Recipe
            {
                Id = 9, Title = "Tomato Basil Soup", Category = "Soups", CategorySlug = "soups",
                Ingredients = ["Tomatoes", "Onion", "Garlic", "Vegetable broth", "Fresh basil", "Cream"],
                Steps = ["Sauté onion and garlic until soft.", "Add chopped tomatoes and broth, simmer 20 minutes.", "Blend until smooth, stir in cream and basil.", "Season and serve with crusty bread."],
                AverageRating = 4.5, RatingCount = 14
            }
        ];
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<Recipe> GetByCategory(string categorySlug)
        => _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetById(int id)
        => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }
}

@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeHub</PageTitle>

@if (string.IsNullOrEmpty(CategorySlug))
{
    <h1>All Categories</h1>
    <p>Select a category from the homepage or navigation to browse recipes.</p>
    <a href="/" class="btn btn-primary">← Back to Categories</a>
}
else
{
    <h1>@CategoryTitle</h1>
    <a href="/" class="btn btn-outline-secondary mb-3">← Back to Categories</a>

    @if (recipes.Count == 0)
    {
        <p class="text-muted">No recipes in this category yet. Be the first to <a href="submit">submit one</a>!</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string? CategorySlug { get; set; }

    private List<Recipe> recipes = [];
    private string CategoryTitle => CategorySlug?.Replace("-", " ") is { } s
        ? System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(s)
        : "";

    protected override void OnParametersSet()
    {
        recipes = string.IsNullOrEmpty(CategorySlug)
            ? []
            : RecipeService.GetByCategory(CategorySlug);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeHub</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="/" class="btn btn-primary">← Back to Home</a>
}
else
{
    <PageTitle>@recipe.Title - RecipeHub</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.CategorySlug">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</p>

    <StarRating RecipeId="recipe.Id" />

    <h2 class="mt-4">Ingredients</h2>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="my-3">
    <strong>Rate this recipe:</strong>
    <span class="ms-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-4 text-decoration-none"
                    @onclick="() => SubmitRating(star)"
                    disabled="@hasRated"
                    title="@star stars">
                @(star <= selectedRating ? "★" : "☆")
            </button>
        }
    </span>
    @if (hasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        if (hasRated) return;
        selectedRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@title" has been added.
        <a href="recipe/@submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
                <option value="beverages">Beverages</option>
                <option value="snacks">Snacks</option>
                <option value="soups">Soups</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="ingredientsText" class="form-control" rows="5"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="stepsText" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
        </div>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private string title = "";
    private string category = "";
    private string ingredientsText = "";
    private string stepsText = "";
    private string? errorMessage;
    private bool submitted;
    private int submittedId;

    private static readonly Dictionary<string, string> CategoryNames = new()
    {
        ["appetizers"] = "Appetizers",
        ["main-courses"] = "Main Courses",
        ["desserts"] = "Desserts",
        ["beverages"] = "Beverages",
        ["snacks"] = "Snacks",
        ["soups"] = "Soups"
    };

    private void HandleSubmit()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        { errorMessage = "Please enter a recipe title."; return; }
        if (string.IsNullOrWhiteSpace(category))
        { errorMessage = "Please select a category."; return; }
        if (string.IsNullOrWhiteSpace(ingredientsText))
        { errorMessage = "Please list at least one ingredient."; return; }
        if (string.IsNullOrWhiteSpace(stepsText))
        { errorMessage = "Please provide at least one step."; return; }

        var recipe = new Recipe
        {
            Title = title.Trim(),
            Category = CategoryNames.GetValueOrDefault(category, category),
            CategorySlug = category,
            Ingredients = ingredientsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = stepsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }
}

