@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="my-3">
    <strong>Rate this recipe:</strong>
    <span class="ms-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-4 text-decoration-none"
                    @onclick="() => SubmitRating(star)"
                    disabled="@hasRated"
                    title="@star stars">
                @(star <= selectedRating ? "★" : "☆")
            </button>
        }
    </span>
    @if (hasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        if (hasRated) return;
        selectedRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}
"}

