toolArgs.file_text:
@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeHub</PageTitle>

@if (string.IsNullOrEmpty(CategorySlug))
{
    <h1>All Categories</h1>
    <p>Select a category from the homepage or navigation to browse recipes.</p>
    <a href="/" class="btn btn-primary">← Back to Categories</a>
}
else
{
    <h1>@CategoryTitle</h1>
    <a href="/" class="btn btn-outline-secondary mb-3">← Back to Categories</a>

    @if (recipes.Count == 0)
    {
        <p class="text-muted">No recipes in this category yet. Be the first to <a href="submit">submit one</a>!</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                ⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string? CategorySlug { get; set; }

    private List<Recipe> recipes = [];
    private string CategoryTitle => CategorySlug?.Replace("-", " ") is { } s
        ? System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(s)
        : "";

    protected override void OnParametersSet()
    {
        recipes = string.IsNullOrEmpty(CategorySlug)
            ? []
            : RecipeService.GetByCategory(CategorySlug);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeHub</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="/" class="btn btn-primary">← Back to Home</a>
}
else
{
    <PageTitle>@recipe.Title - RecipeHub</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.CategorySlug">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</p>

    <StarRating RecipeId="recipe.Id" />

    <h2 class="mt-4">Ingredients</h2>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="my-3">
    <strong>Rate this recipe:</strong>
    <span class="ms-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-4 text-decoration-none"
                    @onclick="() => SubmitRating(star)"
                    disabled="@hasRated"
                    title="@star stars">
                @(star <= selectedRating ? "★" : "☆")
            </button>
        }
    </span>
    @if (hasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int selectedRating;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        if (hasRated) return;
        selectedRating = stars;
        hasRated = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

