@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@title" has been added.
        <a href="recipe/@submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
                <option value="beverages">Beverages</option>
                <option value="snacks">Snacks</option>
                <option value="soups">Soups</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="ingredientsText" class="form-control" rows="5"
                           placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="stepsText" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
        </div>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private string title = "";
    private string category = "";
    private string ingredientsText = "";
    private string stepsText = "";
    private string? errorMessage;
    private bool submitted;
    private int submittedId;

    private static readonly Dictionary<string, string> CategoryNames = new()
    {
        ["appetizers"] = "Appetizers",
        ["main-courses"] = "Main Courses",
        ["desserts"] = "Desserts",
        ["beverages"] = "Beverages",
        ["snacks"] = "Snacks",
        ["soups"] = "Soups"
    };

    private void HandleSubmit()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        { errorMessage = "Please enter a recipe title."; return; }
        if (string.IsNullOrWhiteSpace(category))
        { errorMessage = "Please select a category."; return; }
        if (string.IsNullOrWhiteSpace(ingredientsText))
        { errorMessage = "Please list at least one ingredient."; return; }
        if (string.IsNullOrWhiteSpace(stepsText))
        { errorMessage = "Please provide at least one step."; return; }

        var recipe = new Recipe
        {
            Title = title.Trim(),
            Category = CategoryNames.GetValueOrDefault(category, category),
            CategorySlug = category,
            Ingredients = ingredientsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList(),
            Steps = stepsText.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries).ToList()
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }
}

